import React, { useEffect, useState, useCallback } from 'react';
import { getAssignments, getHolidays, reassignParty, dragAllFromDate, markCompleted, swapAssignments } from '../api';
import { useApp } from '../context/AppContext';
import { format, parseISO, isToday, isSaturday, isSunday, startOfMonth, endOfMonth, eachDayOfInterval, addMonths, subMonths, getDay } from 'date-fns';
import toast from 'react-hot-toast';
import { fireSmallConfetti } from '../utils/confetti';

const CalendarPage = () => {
  const [assignments, setAssignments] = useState([]);
  const [holidays, setHolidays] = useState([]);
  const [currentMonth, setCurrentMonth] = useState(new Date());
  const [loading, setLoading] = useState(true);
  const [draggedAssignment, setDraggedAssignment] = useState(null);
  const [dragAllMode, setDragAllMode] = useState(false);
  const [dragAllFromDateVal, setDragAllFromDateVal] = useState('');
  const [dragAllToDateVal, setDragAllToDateVal] = useState('');
  const [showDragAllModal, setShowDragAllModal] = useState(false);
  const { isAdmin } = useApp();

  const fetchData = useCallback(async () => {
    try {
      const [assignRes, holidayRes] = await Promise.all([getAssignments(), getHolidays()]);
      setAssignments(Array.isArray(assignRes.data) ? assignRes.data : []);
      setHolidays(Array.isArray(holidayRes.data) ? holidayRes.data.map(h => h.holidayDate) : []);
    } catch (err) {
      toast.error('Failed to load data');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetchData(); }, [fetchData]);

  const getAssignmentForDate = (date) => {
    const dateStr = format(date, 'yyyy-MM-dd');
    return assignments.find(a => a.partyDate === dateStr);
  };

  const isHoliday = (date) => holidays.includes(format(date, 'yyyy-MM-dd'));

  const handleDragStart = (assignment) => {
    if (!isAdmin) return;
    setDraggedAssignment(assignment);
  };

  const handleDrop = async (targetDate) => {
    if (!draggedAssignment || !isAdmin) return;
    const dateStr = format(targetDate, 'yyyy-MM-dd');

    if (isSaturday(targetDate) || isSunday(targetDate) || isHoliday(targetDate)) {
      toast.error("Can't assign to weekends or holidays!");
      setDraggedAssignment(null);
      return;
    }

    // Check if there's another assignment at the target
    const existing = getAssignmentForDate(targetDate);
    if (existing && existing.id !== draggedAssignment.id) {
      // Swap them
      try {
        await swapAssignments({ assignmentId1: draggedAssignment.id, assignmentId2: existing.id });
        toast.success(`Swapped ${draggedAssignment.userName} ↔ ${existing.userName} 🔄`);
        fetchData();
      } catch (err) {
        toast.error('Swap failed');
      }
    } else {
      try {
        await reassignParty({ assignmentId: draggedAssignment.id, newDate: dateStr });
        toast.success(`Moved ${draggedAssignment.userName} to ${format(targetDate, 'MMM d')} ✅`);
        fetchData();
      } catch (err) {
        toast.error('Reassignment failed');
      }
    }
    setDraggedAssignment(null);
  };

  const handleDragAllSubmit = async () => {
    if (!dragAllFromDateVal || !dragAllToDateVal) {
      toast.error('Please select both dates');
      return;
    }
    try {
      await dragAllFromDate({ fromDate: dragAllFromDateVal, toDate: dragAllToDateVal });
      toast.success('All assignments moved! 📅');
      setShowDragAllModal(false);
      fetchData();
    } catch (err) {
      toast.error('Failed to move assignments');
    }
  };

  const handleMarkComplete = async (assignment) => {
    if (!isAdmin) return;
    try {
      await markCompleted(assignment.id);
      toast.success(`${assignment.userName}'s party marked complete! 🎉`);
      fireSmallConfetti();
      fetchData();
    } catch (err) {
      toast.error('Failed to update');
    }
  };

  // Build calendar grid
  const monthStart = startOfMonth(currentMonth);
  const monthEnd = endOfMonth(currentMonth);
  const daysInMonth = eachDayOfInterval({ start: monthStart, end: monthEnd });

  // Pad start
  const startPad = getDay(monthStart); // 0=Sun
  const calendarDays = [
    ...Array(startPad).fill(null),
    ...daysInMonth
  ];

  if (loading) {
    return (
      <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '60vh' }}>
        <div style={{ fontSize: '4rem', animation: 'spin 1s linear infinite' }}>🎊</div>
      </div>
    );
  }

  return (
    <div className="page" style={{ maxWidth: '1100px', margin: '0 auto' }}>
      {/* Header */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '24px', flexWrap: 'wrap', gap: '12px' }}>
        <div>
          <h1 style={{ fontSize: '2rem', marginBottom: '4px' }}>📅 Party Calendar</h1>
          <p style={{ color: 'var(--text-muted)', fontSize: '14px' }}>
            {isAdmin ? 'Drag and drop to reassign parties' : 'View the party schedule'}
          </p>
        </div>
        {isAdmin && (
          <button className="btn btn-yellow" onClick={() => setShowDragAllModal(true)}>
            📦 Drag All From Date
          </button>
        )}
      </div>

      {/* Month navigation */}
      <div style={{ display: 'flex', alignItems: 'center', gap: '16px', marginBottom: '20px', justifyContent: 'center' }}>
        <button className="btn btn-ghost" onClick={() => setCurrentMonth(m => subMonths(m, 1))}>← Prev</button>
        <h2 style={{ fontSize: '1.5rem', minWidth: '200px', textAlign: 'center' }}>
          {format(currentMonth, 'MMMM yyyy')}
        </h2>
        <button className="btn btn-ghost" onClick={() => setCurrentMonth(m => addMonths(m, 1))}>Next →</button>
      </div>

      {/* Legend */}
      <div style={{ display: 'flex', gap: '16px', marginBottom: '16px', flexWrap: 'wrap', fontSize: '13px' }}>
        {[
          { color: 'var(--primary)', label: '🎉 Party Day' },
          { color: 'var(--accent)', label: '✅ Completed' },
          { color: 'var(--purple)', label: '📌 Today' },
          { color: 'rgba(255,255,255,0.05)', label: '🚫 Weekend/Holiday' },
        ].map(l => (
          <div key={l.label} style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
            <div style={{ width: 14, height: 14, borderRadius: 4, background: l.color, border: '1px solid rgba(255,255,255,0.1)' }} />
            <span style={{ color: 'var(--text-muted)' }}>{l.label}</span>
          </div>
        ))}
      </div>

      {/* Calendar Grid */}
      <div className="card" style={{ padding: '16px', overflowX: 'auto' }}>
        {/* Day headers */}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '4px', marginBottom: '8px' }}>
          {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(day => (
            <div key={day} style={{
              textAlign: 'center',
              fontSize: '12px',
              fontWeight: 700,
              color: day === 'Sat' || day === 'Sun' ? 'var(--text-muted)' : 'var(--text)',
              padding: '8px',
            }}>
              {day}
            </div>
          ))}
        </div>

        {/* Days */}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '4px' }}>
          {calendarDays.map((day, idx) => {
            if (!day) return <div key={`empty-${idx}`} />;

            const weekend = isSaturday(day) || isSunday(day);
            const holiday = isHoliday(day);
            const today = isToday(day);
            const assignment = getAssignmentForDate(day);
            const notAssignable = weekend || holiday;

            let bg = 'rgba(255,255,255,0.02)';
            let border = '1px solid rgba(255,255,255,0.05)';
            if (today) { bg = 'rgba(132,94,194,0.15)'; border = '1px solid var(--purple)'; }
            if (holiday) { bg = 'rgba(77,150,255,0.08)'; border = '1px dashed rgba(77,150,255,0.3)'; }
            if (weekend) { bg = 'rgba(255,255,255,0.02)'; }
            if (assignment && !assignment.completed) { bg = 'rgba(255,107,107,0.12)'; border = '1px solid rgba(255,107,107,0.4)'; }
            if (assignment?.completed) { bg = 'rgba(107,203,119,0.12)'; border = '1px solid rgba(107,203,119,0.4)'; }

            return (
              <div
                key={format(day, 'yyyy-MM-dd')}
                style={{
                  background: bg,
                  border,
                  borderRadius: '10px',
                  padding: '8px',
                  minHeight: '80px',
                  position: 'relative',
                  cursor: isAdmin && !notAssignable ? 'pointer' : 'default',
                  transition: 'all 0.15s',
                  opacity: notAssignable && !holiday ? 0.4 : 1,
                }}
                onDragOver={e => { if (isAdmin) e.preventDefault(); }}
                onDrop={() => { if (day && !notAssignable) handleDrop(day); }}
              >
                {/* Day number */}
                <div style={{
                  fontSize: '13px',
                  fontWeight: today ? 800 : 600,
                  color: today ? 'var(--purple)' : notAssignable ? 'var(--text-muted)' : 'var(--text)',
                  marginBottom: '4px',
                }}>
                  {format(day, 'd')}
                </div>

                {/* Holiday label */}
                {holiday && (
                  <div style={{ fontSize: '10px', color: 'var(--blue)', fontWeight: 700 }}>
                    🏖️ Holiday
                  </div>
                )}

                {/* Assignment */}
                {assignment && (
                  <div
                    draggable={isAdmin}
                    onDragStart={() => handleDragStart(assignment)}
                    style={{
                      background: assignment.completed
                        ? 'rgba(107,203,119,0.2)'
                        : 'rgba(255,107,107,0.2)',
                      border: `1px solid ${assignment.completed ? 'rgba(107,203,119,0.5)' : 'rgba(255,107,107,0.5)'}`,
                      borderRadius: '6px',
                      padding: '4px 6px',
                      fontSize: '11px',
                      fontWeight: 700,
                      color: assignment.completed ? 'var(--accent)' : 'var(--primary)',
                      cursor: isAdmin ? 'grab' : 'default',
                      display: 'flex',
                      alignItems: 'center',
                      gap: '4px',
                      marginBottom: '4px',
                    }}
                  >
                    {assignment.completed ? '✅' : '🎉'} {assignment.userName}
                  </div>
                )}

                {/* Mark complete button for admin */}
                {isAdmin && assignment && !assignment.completed && isToday(day) && (
                  <button
                    className="btn btn-success"
                    style={{ padding: '2px 6px', fontSize: '10px', marginTop: '2px' }}
                    onClick={() => handleMarkComplete(assignment)}
                  >
                    Done!
                  </button>
                )}
              </div>
            );
          })}
        </div>
      </div>

      {/* Assignments list */}
      <div className="card" style={{ marginTop: '24px' }}>
        <h3 style={{ marginBottom: '16px' }}>📋 Full Party Schedule</h3>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
          {assignments.length === 0 ? (
            <p style={{ color: 'var(--text-muted)', textAlign: 'center', padding: '32px' }}>
              No cycle active. Ask admin to start a new cycle!
            </p>
          ) : (
            assignments.map(a => (
              <div key={a.id} style={{
                display: 'flex',
                alignItems: 'center',
                gap: '16px',
                padding: '12px 16px',
                background: a.isToday
                  ? 'rgba(132,94,194,0.15)'
                  : a.completed
                    ? 'rgba(107,203,119,0.08)'
                    : 'rgba(255,255,255,0.02)',
                border: `1px solid ${a.isToday ? 'var(--purple)' : a.completed ? 'rgba(107,203,119,0.3)' : 'rgba(255,255,255,0.05)'}`,
                borderRadius: '10px',
              }}>
                <div style={{ fontSize: '1.4rem' }}>
                  {a.completed ? '✅' : a.isToday ? '🎊' : '🎉'}
                </div>
                <div style={{ flex: 1 }}>
                  <div style={{ fontWeight: 700, fontSize: '15px', color: a.isToday ? 'var(--purple)' : 'var(--text)' }}>
                    {a.userName}
                    {a.isToday && <span className="badge badge-purple" style={{ marginLeft: '8px' }}>TODAY!</span>}
                  </div>
                  <div style={{ fontSize: '13px', color: 'var(--text-muted)' }}>
                    {format(parseISO(a.partyDate), 'EEEE, MMMM do yyyy')}
                  </div>
                </div>
                {a.completed && <span className="badge badge-green">Done</span>}
                {isAdmin && !a.completed && a.isToday && (
                  <button
                    className="btn btn-success"
                    style={{ padding: '6px 12px', fontSize: '12px' }}
                    onClick={() => handleMarkComplete(a)}
                  >
                    ✅ Mark Done
                  </button>
                )}
              </div>
            ))
          )}
        </div>
      </div>

      {/* Drag All Modal */}
      {showDragAllModal && (
        <div className="modal-overlay" onClick={() => setShowDragAllModal(false)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <h2 style={{ marginBottom: '8px' }}>📦 Drag All Assignments</h2>
            <p style={{ color: 'var(--text-muted)', fontSize: '14px', marginBottom: '24px' }}>
              Move all assignments from a specific date onwards to a new start date.
            </p>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
              <div>
                <label style={{ fontSize: '13px', color: 'var(--text-muted)', display: 'block', marginBottom: '6px' }}>
                  From Date (all assignments on or after this date will move)
                </label>
                <input
                  type="date"
                  className="input"
                  value={dragAllFromDateVal}
                  onChange={e => setDragAllFromDateVal(e.target.value)}
                />
              </div>
              <div>
                <label style={{ fontSize: '13px', color: 'var(--text-muted)', display: 'block', marginBottom: '6px' }}>
                  New Start Date
                </label>
                <input
                  type="date"
                  className="input"
                  value={dragAllToDateVal}
                  onChange={e => setDragAllToDateVal(e.target.value)}
                />
              </div>
              <div style={{ display: 'flex', gap: '12px', marginTop: '8px' }}>
                <button className="btn btn-ghost" style={{ flex: 1, justifyContent: 'center' }} onClick={() => setShowDragAllModal(false)}>
                  Cancel
                </button>
                <button className="btn btn-primary" style={{ flex: 1, justifyContent: 'center' }} onClick={handleDragAllSubmit}>
                  Move All 📦
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default CalendarPage;
